import { useLocation, useNavigate } from "react-router-dom";
import "./styles/Dashboard.css";

function StudentDashboard() {
  const location = useLocation();
  const navigate = useNavigate();

  const name = location.state?.name || "Student";

  return (
    <div className="dashboard-page">
      <h1 className="dashboard-title">Welcome, {name}</h1>

      <div className="dashboard-column">
        <div className="dash-card" onClick={() => navigate("/borrowed")}>
          📚 My Borrowed Books
        </div>

        <div className="dash-card" onClick={() => navigate("/history")}>
          🕘 History by Category
        </div>

        <div className="dash-card" onClick={() => navigate("/books")}>
          🔎 Explore Library
        </div>

        <div className="dash-card" onClick={() => navigate("/wishlist")}>
          ❤️ Wishlist
        </div>
      </div>
    </div>
  );
}

export default StudentDashboard;
